// Cloudflare Worker with SendGrid and Stripe Integration

const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';
const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];
const API_SECRET = 'YOUR_API_SECRET_KEY';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
};

async function handleRequest(request) {
  const url = new URL(request.url);
  const path = url.pathname;

  if (request.method === 'OPTIONS') {
    return new Response(null, {
      headers: corsHeaders,
    });
  }

  if (!authenticateRequest(request)) {
    return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  try {
    if (path === '/api/send-email' && request.method === 'POST') {
      return await handleSendEmail(request);
    } else if (path === '/api/create-payment-intent' && request.method === 'POST') {
      return await handleCreatePaymentIntent(request);
    } else if (path === '/api/create-customer' && request.method === 'POST') {
      return await handleCreateCustomer(request);
    } else if (path === '/api/get-payment-intent' && request.method === 'GET') {
      return await handleGetPaymentIntent(request);
    } else if (path === '/api/refund-payment' && request.method === 'POST') {
      return await handleRefundPayment(request);
    } else if (path === '/api/send-template-email' && request.method === 'POST') {
      return await handleSendTemplateEmail(request);
    } else if (path === '/health' && request.method === 'GET') {
      return jsonResponse({ status: 'healthy', timestamp: new Date().toISOString() });
    } else {
      return jsonResponse({ error: 'Not Found' }, 404);
    }
  } catch (error) {
    return handleError(error);
  }
}

function authenticateRequest(request) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) return false;
  
  const token = authHeader.replace('Bearer ', '');
  return token === API_SECRET;
}

async function handleSendEmail(request) {
  try {
    const body = await request.json();
    const { to, from, subject, text, html } = body;

    if (!to || !from || !subject || (!text && !html)) {
      return jsonResponse({ error: 'Missing required fields: to, from, subject, and text or html' }, 400);
    }

    const emailData = {
      personalizations: [
        {
          to: Array.isArray(to) ? to.map(email => ({ email })) : [{ email: to }],
        },
      ],
      from: { email: from },
      subject: subject,
    };

    if (html) {
      emailData.content = [{ type: 'text/html', value: html }];
    } else {
      emailData.content = [{ type: 'text/plain', value: text }];
    }

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(emailData),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${errorText}`);
    }

    return jsonResponse({ 
      success: true, 
      message: 'Email sent successfully',
      messageId: response.headers.get('X-Message-Id')
    });
  } catch (error) {
    throw new Error(`Email sending failed: ${error.message}`);
  }
}

async function handleSendTemplateEmail(request) {
  try {
    const body = await request.json();
    const { to, from, templateId, dynamicTemplateData } = body;

    if (!to || !from || !templateId) {
      return jsonResponse({ error: 'Missing required fields: to, from, templateId' }, 400);
    }

    const emailData = {
      personalizations: [
        {
          to: Array.isArray(to) ? to.map(email => ({ email })) : [{ email: to }],
          dynamic_template_data: dynamicTemplateData || {},
        },
      ],
      from: { email: from },
      template_id: templateId,
    };

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(emailData),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${errorText}`);
    }

    return jsonResponse({ 
      success: true, 
      message: 'Template email sent successfully',
      messageId: response.headers.get('X-Message-Id')
    });
  } catch (error) {
    throw new Error(`Template email sending failed: ${error.message}`);
  }
}

async function handleCreatePaymentIntent(request) {
  try {
    const body = await request.json();
    const { amount, currency = 'usd', description, metadata } = body;

    if (!amount || amount <= 0) {
      return jsonResponse({ error: 'Invalid amount' }, 400);
    }

    const params = new URLSearchParams({
      amount: amount.toString(),
      currency: currency,
    });

    if (description) {
      params.append('description', description);
    }

    if (metadata) {
      Object.keys(metadata).forEach(key => {
        params.append(`metadata[${key}]`, metadata[key]);
      });
    }

    const response = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.status}`);
    }

    return jsonResponse({
      success: true,
      paymentIntent: {
        id: data.id,
        clientSecret: data.client_secret,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
      },
    });
  } catch (error) {
    throw new Error(`Payment intent creation failed: ${error.message}`);
  }
}

async function handleCreateCustomer(request) {
  try {
    const body = await request.json();
    const { email, name, description, metadata } = body;

    if (!email) {
      return jsonResponse({ error: 'Email is required' }, 400);
    }

    const params = new URLSearchParams({
      email: email,
    });

    if (name) params.append('name', name);
    if (description) params.append('description', description);

    if (metadata) {
      Object.keys(metadata).forEach(key => {
        params.append(`metadata[${key}]`, metadata[key]);
      });
    }

    const response = await fetch('https://api.stripe.com/v1/customers', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.status}`);
    }

    return jsonResponse({
      success: true,
      customer: {
        id: data.id,
        email: data.email,
        name: data.name,
        created: data.created,
      },
    });
  } catch (error) {
    throw new Error(`Customer creation failed: ${error.message}`);
  }
}

async function handleGetPaymentIntent(request) {
  try {
    const url = new URL(request.url);
    const paymentIntentId = url.searchParams.get('id');

    if (!paymentIntentId) {
      return jsonResponse({ error: 'Payment intent ID is required' }, 400);
    }

    const response = await fetch(`https://api.stripe.com/v1/payment_intents/${paymentIntentId}`, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
      },
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.status}`);
    }

    return jsonResponse({
      success: true,
      paymentIntent: {
        id: data.id,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
        created: data.created,
        description: data.description,
      },
    });
  } catch (error) {
    throw new Error(`Failed to retrieve payment intent: ${error.message}`);
  }
}

async function handleRefundPayment(request) {
  try {
    const body = await request.json();
    const { paymentIntentId, amount, reason } = body;

    if (!paymentIntentId) {
      return jsonResponse({ error: 'Payment intent ID is required' }, 400);
    }

    const params = new URLSearchParams({
      payment_intent: paymentIntentId,
    });

    if (amount) params.append('amount', amount.toString());
    if (reason) params.append('reason', reason);

    const response = await fetch('https://api.stripe.com/v1/refunds', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(`Stripe API error: ${data.error?.message || response.status}`);
    }

    return jsonResponse({
      success: true,
      refund: {
        id: data.id,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
        reason: data.reason,
      },
    });
  } catch (error) {
    throw new Error(`Refund failed: ${error.message}`);
  }
}

function handleError(error) {
  console.error('Error:', error);
  
  const errorResponse = {
    error: error.message || 'Internal Server Error',
    timestamp: new Date().toISOString(),
  };

  let statusCode = 500;
  
  if (error.message.includes('Missing required fields') || error.message.includes('Invalid')) {
    statusCode = 400;
  } else if (error.message.includes('Unauthorized')) {
    statusCode = 401;
  } else if (error.message.includes('Not Found')) {
    statusCode = 404;
  }

  return jsonResponse(errorResponse, statusCode);
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status: status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders,
    },
  });
}

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});